module sync_counter(obf_clk, enable, reset, count);

    input obf_clk;
    input enable;
    input reset;
    output [3:0] count;
    reg [3:0] count;
    initial count = 0;

    always @(posedge obf_clk)
        begin
            if (reset)
                count <= 0;
            else if (enable)
                count <= count + 1;
        end

endmodule
